return await (async function(eda) {
  const fixtureName = '__codex_example___PCB_PrimitivePolyline_modify_' + Date.now();
  const currentProject = await eda.dmt_Project.getCurrentProjectInfo();
  if (!currentProject) { throw new Error('当前没有打开工程，先补齐环境再调试这个案例。'); }
  const currentDocument = await eda.dmt_SelectControl.getCurrentDocumentInfo();
  if (!currentDocument) {
    throw new Error('当前没有活动文档，先打开一个可操作的文档页。');
  }
  if (currentDocument.documentType !== 3) {
    throw new Error('当前文档类型不是 PCB，请先切到 PCB 再运行这个案例。');
  }
  const fixturePolygon = eda.pcb_MathPolygon.createPolygon(['R', 1000, 1000, 300, 200, 0, 0]);
  if (!fixturePolygon) { throw new Error('无法创建用于案例演示的测试多边形。'); }
  const createdPrimitive = await eda.pcb_PrimitivePolyline.create(
    'GND',
    1,
    fixturePolygon,
    10,
    false,
  );
  const primitiveId = createdPrimitive?.getState_PrimitiveId?.() ?? createdPrimitive?.primitiveId ?? createdPrimitive?.id;
  if (!primitiveId) { throw new Error('没有创建出可用于修改的测试图元。'); }
  const property = {
    lineWidth: 12,
  };
  try {
    const before = await eda.pcb_PrimitivePolyline.get(primitiveId);
    const result = await eda.pcb_PrimitivePolyline.modify(primitiveId, property);
    const after = await eda.pcb_PrimitivePolyline.get(primitiveId);
    return {
      fixtureName,
      primitiveId,
      property,
      before,
      result,
      after,
      cleanupStrategy: 'auto',
    };
  } finally {
    if (primitiveId) { await eda.pcb_PrimitivePolyline.delete([primitiveId]); }
  }
})(eda);
